// ══════════════════════════════════════════════════════════════════
//  🎭 Orpheus · 陪伴脚本  v5.5.2-loopfix  by Anrrow
//  · 右侧抽屉+内嵌 Tab · 预设分组开关 · 净化引擎直接写回正文
//  · 分类净化规则 · 内置词库可停用 · 安卓触屏悬浮窗修复 · 句子级净化
// ══════════════════════════════════════════════════════════════════

(function () {
  const ROOT = window.parent && window.parent.document ? window.parent : window;
  const DOC = ROOT.document;
  const ORPHEUS_VERSION = '5.5.2-loopfix';
  try { if (typeof ROOT.__ORPHEUS_CLEANUP__ === 'function') ROOT.__ORPHEUS_CLEANUP__('reload'); } catch(e) { console.warn('[Orpheus] cleanup before reload failed:', e); }
  ['cc-btn','cc-overlay','cc-drawer','cc-bubble','cc-ext-menu-item','cc-sb'].forEach(id => { try { DOC.getElementById(id)?.remove(); } catch(e) {} });
  ROOT.__ORPHEUS_INIT__ = true;
  ROOT.__ORPHEUS_VERSION__ = ORPHEUS_VERSION;
  const ccTimers = [];
  const ccObservers = [];
  const ccCleanupListeners = [];
  function ccSetTimeout(fn, ms){ const id = ROOT.setTimeout(fn, ms); ccTimers.push({type:'timeout', id}); return id; }
  function ccSetInterval(fn, ms){ const id = ROOT.setInterval(fn, ms); ccTimers.push({type:'interval', id}); return id; }
  function addCleanupListener(target, type, fn, opts){
    try { target?.addEventListener?.(type, fn, opts); ccCleanupListeners.push({target,type,fn,opts}); } catch(e) {}
  }

  // ─── 工具 ─────────────────────────────────────────────────
  function isMobile() {
    return (DOC.documentElement.clientWidth||ROOT.innerWidth) < 768
      || /Mobi|Android|iPhone|iPad/i.test(navigator.userAgent);
  }
  function getFrameOffset() {
    try { if(!window.frameElement) return {left:0,top:0}; const r=window.frameElement.getBoundingClientRect(); return {left:r.left,top:r.top}; } catch(e) { return {left:0,top:0}; }
  }
  function positionBubble() {
    const vw=DOC.documentElement.clientWidth||ROOT.innerWidth, vh=DOC.documentElement.clientHeight||ROOT.innerHeight;
    const br=$btn.getBoundingClientRect(), bw=$bubble.offsetWidth||260, bh=$bubble.offsetHeight||60, GAP=12;
    const dw = drawerOpen ? (isMobile() ? ROOT.innerWidth*0.88 : 340) : 0;
    let left=br.left-bw-GAP; if(left<8) left=Math.min(br.right+GAP, vw-bw-dw-8);
    let top=br.top+br.height/2-bh/2; if(top<8)top=8; if(top+bh>vh-8)top=vh-bh-8;
    $bubble.style.cssText+=`;right:auto!important;bottom:auto!important;left:${left}px!important;top:${top}px!important;`;
  }
  const pick = arr => arr[Math.floor(Math.random()*arr.length)];
  function esc(s){ return String(s).replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c])); }

  // ─── 图标 ──────────────────────────────────────────────────
  const ICON_URL = 'https://imagetourl.cloud/rrkvr12d.jpg';
  function oImg(size) {
    const r=Math.round(size*0.22);
    return `<img src="${ICON_URL}" width="${size}" height="${size}" style="border-radius:${r}px;object-fit:contain;display:block;" onerror="this.outerHTML='<span style=font-size:${Math.round(size*.65)}px>🎭</span>'">`;
  }

  // ─── 配置 ──────────────────────────────────────────────────
  const STORE_KEY = 'orpheus_v4';
  const DEFAULTS = {
    apiKey:'', city:'Petaling Jaya', interval:30, rest:true, weather:true,
    openaiKey:'', aiBaseUrl:'https://api.openai.com/v1', aiModel:'', aiInterval:5, aiEnabled:true,
    idle:true, idleMins:8, timeGreet:true, strategyEnabled:true, nickname:'',
    personality:'tsundere', customPersonality:'',
    purifyEnabled:false, purifyAiEnabled:true, autoFixEnabled:true, autoFixMaxRounds:1, groupSeparator:'/', floatEnabled:true, extensionMenuEnabled:true,
  };
  let cfg = {...DEFAULTS};
  try { Object.assign(cfg, JSON.parse(ROOT.localStorage.getItem(STORE_KEY)||'{}')); } catch(e) {}
  function saveCfg() { ROOT.localStorage.setItem(STORE_KEY, JSON.stringify(cfg)); }
  const startTime = Date.now();

  // ─── 禁词表 ────────────────────────────────────────────────
  const FORB_WORDS = [
    '无力感','面无表情','剧烈','极度','深深','震惊','紧绷','收紧','死死攥住',
    '仿佛','好像在','指节','指尖泛白','指尖发白','身体诚实','胸腔震动',
    '涟漪','石子','心湖','小兽','野兽','光圈','光斑','深潭','深海',
    '刀刃','烙印','炸开','炸裂','一丝','一缕','一抹','猛地','瞬间','刹那',
    '狡黠','玩味','都在诉说','不容置疑','无法抗拒','前所未有','无法形容',
    '格格不入','审视','荷尔蒙','邪肆','邪魅','砂纸','羽毛','吞没','熠熠',
    '矜持','精准','精确','灼热','滚烫','沸腾','炙热','攥紧拳头','握紧',
    '僵硬','一片空白','电流','闪电','如释重负','咬紧','咬牙','木偶','某种','沙哑',
    '突然','不由得','不禁','忍不住','一时间','突然觉得','莫名感到','似乎',
    '一股暖流','心头一紧','失落感','挫败感','孤独感','氛围','难以言喻','不可名状',
    '深吸一口气','轻叹一声','舔了舔嘴唇'
  ];
  const FORB_ANATOMY = [
    '粘膜','筋膜','韧带','肌腱','软骨','括约肌','胰腺','胆囊','卵巢','前列腺',
    '血管','动脉','静脉','神经','淋巴','虹膜','锁骨','肋骨','五指','肩胛',
    '骨节','背脊','脊背','颧骨','胯骨','腰椎','颈椎','胸椎','尾椎','髋骨',
    '耻骨','骨缝','脉搏','喉结','鼓膜'
  ];
  const FORB_PATS = [
    {re:/(^|[^是])(?:已经|已|早就)?不是[^。！？\n]{1,50}?(?:了)?(?:[，,、；;]\s*)?(?:是|而是|其实是)/,label:'否定-转折'},
    {re:/(?:不再是|再不是)[^。！？\n]{1,50}?(?:[，,、；;]\s*)?(?:是|而是|更像|更接近|倒像|倒不如说)/,label:'否定-转折'},
    {re:/并非[^。！？\n]{1,50}?(?:而是|只是|不过是|更像|更接近|倒像)/,label:'否定-转折'},
    {re:/不像[^。！？\n]{1,40}?(?:像|更像|倒像)/,label:'不像A像B'},
    {re:/与其说[^。！？\n]{1,50}?不如说/,label:'与其说…不如说'},
    {re:/(?:算不上|说不上|称不上|不完全是|不至于|不算|谈不上|够不上)[^。！？\n]{0,50}?(?:[，,、；;]\s*)?(?:只是|更像|倒像|不过是|更接近|倒不如说|是)/,label:'否定校准'},
    {re:/(?:不是|也不是|倒也不是|并非|不像|不算|算不上|说不上|称不上|不完全是|不至于|谈不上|够不上|没有)[^。！？\n]{0,50}?(?:只是|更像|倒像|不过是|更接近|倒不如说)/,label:'重框架连接'},
    {re:/(?:既没有|没有)[^。！？\n]{1,30}?也没有[^。！？\n]{1,30}/,label:'缺席校准'},
    {re:/也不是|倒也不是|说不上是/,label:'否定软化'},
    {re:/那是[^，。！？\n]{1,20}的感觉/,label:'那是…的感觉'},
    {re:/那种[^的，。！？\n]{1,15}的感觉/,label:'那种X的感觉'},
    {re:/(?:更关键的是|我知道|我看见)(?:[^，。])/,label:'叙述者介入'},
    {re:/(?:终于|总算|到底)(?:等到|才|让|来|走|完)/,label:'解脱标记'},
    {re:/(?:\d+|[一二两三四五六七八九十半]+)(?:秒|次|下(?!午|班|课)|拍|步|厘米|毫米|个字)/,label:'数字精确量'},
    {re:/[二三四五六七八九十]分[^，。！？\n]{0,8}意/,label:'X分Y意'},
    {re:/语气(?:平淡|柔软|低沉|冷淡).{0,6}(?:像|就像)/,label:'语气比喻'},
    {re:/(?:像|跟|和|如同|仿佛)(?:是)?(?:在)?(?:聊|讨论|谈论|谈|说)(?:起)?[^。！？\n]{0,12}(?:天气|一样|似的|那样|般)/,label:'比喻性情态状语'},
    {re:/用(?:聊|讨论|谈|说)[^。！？\n]{0,10}的(?:口气|口吻|语气|腔调|态度)/,label:'比喻性情态状语'},
    {re:/(?:冷冷|淡淡|愤怒地|微笑|温柔|平静|低沉|沙哑|冰冷|轻声|厉声)(?:地)?(?:道|说|开口|问|吼|喊|笑道)/,label:'情绪标签式对话'},
    {re:/(?:他|她|你|我)?是那种[^。！？\n]{1,40}的人/,label:'翻译腔人设句'},
    {re:/呈现出[^。！？\n]{1,40}的状态/,label:'翻译腔状态句'},
    {re:/(?:深吸一口气|轻叹一声|舔了舔嘴唇)/,label:'无功能呼吸叹气'},
    {re:/(?:^|[。！？!?\n])\s*[^。！？!?\n，,、；;]{1,4}[。！？!?]/,label:'短句碎片'},
    {re:/[，,、；;]\s*[^，,、；;。！？!?\n]{1,4}的(?=[，,、；;。！？!?\n]|$)/,label:'形容词尾巴碎片'},
    {re:/以一种[^。！？\n]{1,40}(?:方式|姿态|状态)/,label:'叙述重量-方式腔'},
    {re:/近乎[^。！？\n]{1,30}的方式/,label:'叙述重量-方式腔'},
    {re:/用的那种[^。！？\n]{1,50}/,label:'动作后注释'},
    {re:/(?:呈现|表现|显露|暴露)出[^。！？\n]{1,40}(?:状态|姿态|态势)/,label:'翻译腔状态句'},
  ];

  function scanForbidden(text) {
    const found=[];
    getPurifyWordMatches(text).sort((a,b)=>b.word.length-a.word.length).forEach(item=>{
      if(item.word && !found.includes(item.word)) found.push(item.word);
    });
    getAllPatternRules().forEach(p=>{
      const tag='【'+p.label+'】';
      const re = new RegExp(p.re.source, p.re.flags.replace('g',''));
      if(re.test(text)&&!found.includes(tag)) found.push(tag);
    });
    return found;
  }


  // ─── 旧版直替映射已停用 ───────────────────────────────
  // v5.1 起不再本地机械替换；词条和句式只作为“告诉 AI 怎么改”的规则。
  const DEFAULT_PURIFY_MAP = {};

  // ─── 净化规则：词条和句式分开管理（指令式，不做机械直替） ──────
  const CUSTOM_WORDS_KEY = 'orpheus_custom_words';
  const CUSTOM_PATTERNS_KEY = 'orpheus_custom_patterns';
  const BUILTIN_WORD_RULES_KEY = 'orpheus_builtin_word_rules_v52';
  const BUILTIN_PATTERN_RULES_KEY = 'orpheus_builtin_pattern_rules_v52';
  const DISABLED_BUILTINS_KEY = 'orpheus_disabled_builtins_v52';
  const PURIFY_SYSTEM_PROMPT_KEY = 'orpheus_purify_system_prompt_v544_scope_style';
  const CATEGORY_RULES_KEY = 'orpheus_category_rules_v53';

  const WORD_RULE_DEFAULT = '八股词统一规则：只处理命中词所在的最小短句/分句。能删且该分句仍通顺时，直接删除；不能一律换成同样模板化的近义词（例如不要把“猛地”机械换成“突然”）。替换后分句明显不通时，只做最小补缝，让这一小段顺口一点。严禁清洗整段、严禁润色未命中的信息，不要新增情节，不要改变人物动作、语义和视角。';
  const ANATOMY_RULE_DEFAULT = '医学/解剖/专业词统一规则：仅在非医疗、非专业场景处理。优先把命中的词改成日常部位、自然体感或动作描写；不要百科解释，不要保留医学腔。严禁造不存在或生硬的新词，例如把“颧骨”改成“颧头/颧弧/颧侧/颧面”；不要新增原文没有的解剖部位，例如原文只命中“颧骨”时不要擅自加“下颌线”。若替换后不顺，只做命中词附近最小补缝。';
  const PURIFY_SYSTEM_PROMPT_DEFAULT = [
    '你是中文小说净化工具。用户给你的是"检测项 + 修改规则"，你必须根据规则结合上下文做最小改动。',
    '只输出 JSON 对象，格式：{"原句或分句":"改写后的原句或分句"}，禁止任何解释、Markdown、代码块。',
    '',
    '**作用域铁律：只修命中片段**',
    '* key 必须原样照抄，不改一字一标点。',
    '* 每个 key 是一条被脚本截出的最小原文单位：通常是命中词所在分句，少数句式才是完整句。',
    '* value 必须对应同一个 key 的最小改写，不能越界清洗整段，不能重写 key 外的句子。',
    '* 只处理 label/rule 指向的问题词、问题片段或病句结构；key 里没有问题的动作、信息、人物称谓、顺序必须尽量原样保留。',
    '* 若只替换/删除命中词会让这一小段不通，才允许在命中词前后很小范围补缝；禁止把原文改成全新表达。',
    '* 没问题或无法有效改写的条目，不要输出；禁止 value 等于 key。',
    '* 禁止扩写新情节，禁止新增原文没有的意象、道具、心理解释、环境描写；只从原句已有材料里删减、合并、顺句。',
    '',
    '**解剖词安全线**',
    '* 解剖/医学词要改成日常表达，但绝对不能造新词、怪词或更专业的替代词。',
    '* 例：“颧骨”优先改成“脸颊/脸侧/面颊”，禁止改成“颧头、颧弧、颧侧、颧面”；“肋骨”优先改成“腰侧/肋下/身侧”，不要扩写成新的身体结构。',
    '* 禁止新增原文没有的解剖部位或线条审美词：如下颌线、下颌、弧度、骨线、骨面。若无法自然替换，宁可保留或删除该净化项，也不要写出怪句。',
    '',
    '**风格锚定**',
    '* 你会收到 style_hint / style_sample。它们只用于保持当前预设文风、句长、词汇密度和节奏，不是让你重新润色。',
    '* 改写后必须像原文上下文自然长出来：不要突然变成总结腔、古早网文腔、翻译腔、过度白描或过度文学化。',
    '* 风格优先级低于作用域铁律：即使 style_sample 很漂亮，也不得借机改写无关内容。',
    '',
    '**短碎片合并**',
    '* 凡 4 字以内的独立短句，或逗号/顿号/分号切出来的形容词尾巴片段，都不要孤零零保留。',
    '* 例：“湿的，” “热的。” “很轻。” “发烫的，”——必须并入前后动作、触感或场景事实；能删则删，不能删就改成顺滑的句内成分。',
    '* 不要把碎片改成新的抒情句；只让原句更顺。',
    '',
    '**数字精确量模糊**',
    '* 小单位计数要模糊：三秒、五步、两拍、几厘米、三下、两次 → 片刻、几步、顿了顿、贴近些、碰了碰。',
    '* 例外：一天及以上的时间跨度可以保留，如三年、一星期、两个月后。',
    '* 真正剧情必需的计数可以保留，但不要空心精确。',
    '',
    '**叙事重量**',
    '* 每一句必须推进剧情、显露人物、制造张力或提供必要感官信息；纯重复、复述已知事实、解释状态如何形成的废句，删掉或并入主动作。',
    '* 禁止“先标签后解释”：不要先说状态/感觉/方式，再解释它是什么；直接写可见动作、身体状态或场景事实。',
    '* 禁止 POST-ACTION ANNOTATION：动作写完后，不要再接一句解释它的性质、力道、意图、质量。例：“她拍了他胸口一巴掌，用的那种不太用力但很响的巴掌。”应把细节写进动作本身，或删除后半句。',
    '* 禁止 summary-first paragraph opener：段首不要先下总结标签，再展开解释。',
    '',
    '**否定对比必杀**',
    '凡是"不是…而是""并非…倒是""算不上…只是""不像是…就是"这种先否后转的句式，必须改成肯定句。不要写"不是A，而是B"；直接把B变成具体的身体反应、动作或可感知的事实。',
    '普通事实否定如"他没有开口""她不在屋里"保留，不要误杀。',
    '',
    '**中文质量与去AI味**',
    '避免翻译腔、定义句、旁观镜头、空心精确、无功能动作、声音/情绪标签。额外禁止以下AI高频套话，必须改成具体的感官、动作或细节：',
    '* 虚词判断：不由得、不禁、忍不住、一时间、突然觉得、莫名感到、仿佛、似乎',
    '* 抽象感受名词：一股暖流、心头一紧、失落感、挫败感、孤独感、氛围、某种、难以言喻、不可名状',
    '* 情绪标签式对话：冷冷道、淡淡说、愤怒地吼、微笑道……一律换成小动作、神态或语气带来的生理反应',
    '* 翻译腔骨架："他是那种……的人""那是一种……的感觉""呈现出……的状态""以一种……的方式"——直接删掉骨架，写出事情本身',
    '* 无功能的呼吸叹气：深吸一口气、轻叹一声、舔了舔嘴唇，除非它真正推动了动作',
    '',
    '正面要求：贴合上下文风格，只让命中单位更干净、更通顺；不要为了净化把原作者的句子清洗成另一种文风。'
  ].join('\n');
  const DEFAULT_WORD_INSTRUCTIONS = Object.assign({}, ...FORB_WORDS.map(w => ({[w]: WORD_RULE_DEFAULT})), {
    '无力感':'删除情绪标签，改成此刻可感知的身体反应或动作。',
    '面无表情':'不要外部镜头贴标签，改成角色此刻能感到/看到的细节。',
    '震惊':'删除抽象情绪标签，改成短暂停顿、呼吸、眼神或手上动作。',
    '仿佛':'能删则删；如果是空泛比喻，改成实感描写。',
    '好像在':'去掉不确定框架，直接写当下发生的动作或感受。',
    '身体诚实':'删除套话，改成具体反应。',
    '涟漪':'删除文艺腔比喻，换成朴素、可触可见的反应。',
    '心湖':'删除抽象比喻，回到人物身体和场景。',
    '小兽':'删除套话比喻，改成具体动作或感受。',
    '野兽':'删除套话比喻，改成具体动作或感受。',
    '光圈':'避免滤镜感，改成直接的光线/视线描写。',
    '光斑':'避免滤镜感，改成直接的光线/视线描写。',
    '深潭':'删除眼睛/情绪套话比喻，改成实际神态或视线。',
    '深海':'删除情绪套话比喻，改成实际感受。',
    '刀刃':'删除夸张比喻，改成具体触感或语义压力。',
    '烙印':'删除套话比喻，改成留在记忆/皮肤/感受里的具体痕迹。',
    '炸开':'避免夸张情绪动词，改成更平实的突然反应。',
    '炸裂':'避免夸张情绪动词，改成更平实的突然反应。',
