  function safeRegExp(source, flags){
    try { return new RegExp(source, flags || ''); } catch(e) { return null; }
  }
  function reEsc(s){ return String(s || '').replace(/[.*+?^${}()|[\]\\]/g,'\\$&'); }
  function hasCustomWordWildcard(word){ return /(?:xx|XX|ＸＸ|\*|＊)/.test(String(word || '')); }
  function cjkTail(s, maxLen){
    const m = String(s || '').match(new RegExp('[\\u3400-\\u9FFF\\uF900-\\uFAFF]{1,' + (maxLen || 6) + '}$'));
    return m ? m[0] : '';
  }
  function shrinkLeadingWildcardTerm(stem, suffix){
    stem = String(stem || ''); suffix = String(suffix || '');
    if(!stem || !suffix) return '';
    // “她的腕骨 / 他的腰椎”这类，先切掉常见虚词和结构助词之前的内容。
    const cutChars = '的地得和与及或在把被将向从对给里上中下前后内外旁边侧';
    let cut = -1;
    for(let i=0;i<stem.length;i++) if(cutChars.includes(stem[i])) cut = i;
    if(cut >= 0 && cut < stem.length - 1) stem = stem.slice(cut + 1);
    const known = [
      '肩胛','胸椎','腰椎','颈椎','尾椎','骶椎','脊椎','颧骨','锁骨','肋骨','腕骨','髋骨','胯骨','额骨','眉骨','鼻骨','颌骨','颚骨','颞骨','枕骨','顶骨',
      '肩','胛','颧','锁','肋','腕','髋','胯','额','眉','鼻','颌','颚','颞','枕','顶','颅','脊','尾','颈','胸','腰','骶','指','趾','掌','跖','臂','腿','膝','踝','手','脚','背'
    ].sort((a,b)=>b.length-a.length);
    for(const k of known){
      if(stem.endsWith(k)){
        const term = k + suffix;
        // 避免 “胸椎椎” 这类重复后缀。
        return term.replace(new RegExp('(' + reEsc(suffix) + '){2,}$'), suffix);
      }
    }
    // 默认只取最后 1 个汉字 + 后缀，避免把“她的腕骨”扫成“她的腕骨”。
    return stem.slice(-1) + suffix;
  }
  function customWildcardMatches(text, item){
    const raw = String(item?.word || '').trim();
    const s = String(text || '');
    if(!raw || !s || !hasCustomWordWildcard(raw)) return [];
    const out = [];
    const push = (word) => {
      word = String(word || '').trim();
      if(word && word !== raw && s.includes(word) && !out.includes(word)) out.push(word);
    };

    // 最常用写法：xx骨 / xx椎 / *骨。这里按“短词后缀”处理，命中实际出现的短词。
    const lead = raw.match(/^(?:(?:xx|XX|ＸＸ)|\*|＊)+(.+)$/);
    if(lead && lead[1]){
      const suffix = lead[1];
      let from = 0;
      while(from < s.length){
        const idx = s.indexOf(suffix, from);
        if(idx < 0) break;
        const stem = cjkTail(s.slice(0, idx), 6);
        push(shrinkLeadingWildcardTerm(stem, suffix));
        from = idx + Math.max(1, suffix.length);
      }
      return out;
    }

    // 兜底：把 xx/* 当成 1~6 个汉字。但只适合比较明确的前后缀写法。
    const source = reEsc(raw).replace(/(?:xx|XX|ＸＸ|\\\*|＊)+/g, '[\\u3400-\\u9FFF\\uF900-\\uFAFF]{1,6}');
    const re = safeRegExp(source, 'g');
    if(!re) return out;
    let m;
    while((m = re.exec(s))){ push(m[0]); if(!m[0]) re.lastIndex++; }
    return out;
  }
  function getPurifyWordMatches(text){
    const s = String(text || '');
    const byWord = new Map();
    const add = (word, type, instruction, source) => {
      word = String(word || '').trim();
      if(!word || !s.includes(word)) return;
      const old = byWord.get(word);
      if(old){
        if(type === 'anatomy') old.type = 'anatomy';
        if(instruction && !old.instructions.includes(instruction)) old.instructions.push(instruction);
        return;
      }
      byWord.set(word, {word, type:type === 'anatomy' ? 'anatomy' : 'word', instructions:instruction?[instruction]:[], source});
    };
    getActiveForbWords().forEach(w => add(w, 'word', getWordInstruction(w, 'word'), 'builtin'));
    getActiveForbAnatomy().forEach(w => add(w, 'anatomy', getWordInstruction(w, 'anatomy'), 'builtin'));
    customPurifyWords.forEach(item => {
      const type = item.type === 'anatomy' ? 'anatomy' : 'word';
      const instruction = String(item.instruction || getCategoryRule(type)).trim();
      if(hasCustomWordWildcard(item.word)) customWildcardMatches(s, item).forEach(w => add(w, type, instruction, 'custom-wildcard'));
      else add(item.word, type, instruction, 'custom');
    });
    return [...byWord.values()].map(x => Object.assign(x, {instruction:x.instructions.join('\n')}));
  }
  function getCustomForbWords() {
    return customPurifyWords.filter(i => i.type === 'word').map(i => i.word).filter(Boolean);
  }
  function getCustomForbAnatomy() {
    return customPurifyWords.filter(i => i.type === 'anatomy').map(i => i.word).filter(Boolean);
  }
  function getCustomPatternRules(){
    return customPurifyPatterns.map(item => {
      const re = safeRegExp(item.pattern, item.flags || '');
      return re ? {re, label:item.label, instruction:item.instruction, custom:true, pattern:item.pattern, flags:item.flags || ''} : null;
    }).filter(Boolean);
  }
  function getAllPatternRules(){ return [...FORB_PATS.filter(p => !isBuiltinPatternDisabled(p.label)), ...getCustomPatternRules()]; }
  function getWordInstruction(word, type){
    // v5.3 降低复杂度：词条只负责“检测到什么”，具体怎么改只看分类规则。
    // 例如用户能接受“锁骨”时，直接把内置词“锁骨”停用；不再给每个词单独写提示词。
    return getCategoryRule(type === 'anatomy' || FORB_ANATOMY.includes(word) ? 'anatomy' : 'word');
  }
  function getPatternInstruction(label){
    const custom = customPurifyPatterns.find(i => i.label === label);
