  function normalizePurifyMap(map) {
    const out = {};
    Object.entries(map || {}).forEach(([orig, repl]) => {
      if (orig) out[String(orig)] = repl == null ? '' : String(repl);
    });
    return out;
  }

  function getContextParts(raw) {
    const parts = [];
    String(raw || '').replace(/<context>([\s\S]*?)<\/context>/gi, (_, body) => {
      parts.push(body);
      return _;
    });
    return parts;
  }

  function getPurifyTextFromRaw(raw) {
    const parts = getContextParts(raw);
    return parts.length ? parts.map(x => x.trim()).join('\n\n') : '';
  }

  function applyMapToContext(raw, map) {
    const normalized = normalizePurifyMap(map);
    let touched = false;
    const replaced = String(raw || '').replace(/(<context>)([\s\S]*?)(<\/context>)/gi, (all, open, body, close) => {
      let next = guardedApplyMap(body, normalized);
      if (next !== body) touched = true;
      return open + next + close;
    });
    return { text: replaced, scoped: touched };
  }

  function getMesIndexFromEl(mesEl) {
