  function getLatestAiTarget() {
    const ctx = ROOT.SillyTavern?.getContext();
    const chat = ctx?.chat;
    if (!Array.isArray(chat) || !chat.length) return null;

    // 先按聊天 DOM 的真实顺序取最后一条 AI/角色消息，不受滚动可见区域影响。
    const domMsgs = [...DOC.querySelectorAll('#chat .mes')].reverse();
    for (const mesEl of domMsgs) {
      if (mesEl.getAttribute('is_user') === 'true' || mesEl.dataset?.isUser === 'true') continue;
      const target = getTargetMessageFromEl(mesEl);
      const msg = target?.chat?.[target.idx];
      if (!msg || msg.is_user || msg.is_system || !String(msg.mes || '').trim()) continue;
      return { ...target, raw: msg.mes || '' };
    }

    // DOM 没取到时，再回退到 SillyTavern chat 数组的最后一条角色消息。
    for (let idx = chat.length - 1; idx >= 0; idx--) {
      const msg = chat[idx];
      if (!msg || msg.is_user || msg.is_system || !String(msg.mes || '').trim()) continue;
      const mesEl = getMesElByIndex(idx);
      return { ctx, chat, idx, raw: msg.mes || '', mesEl };
    }
    return null;
  }

  function cloneRegexGlobal(re) {
    return new RegExp(re.source, re.flags.includes('g') ? re.flags : re.flags + 'g');
  }

  // 对话/心声标记：净化单元绝不跨越或包含这些符号，保证 AI 永远碰不到引号星号。
  const QUOTE_OPEN = '\u201c\u2018\u0022\u0027\u300c\u300e\u300a\uff08([`*';
  const QUOTE_CLOSE = '\u201d\u2019\u0022\u0027\u300d\u300f\u300b\uff09)]`*';
  function expandToSentence(text, start, end) {
    const leftMarks = '\n。！？!?' + QUOTE_OPEN + QUOTE_CLOSE;
    const stopMarks = '。！？!?';
    const rightStops = stopMarks + QUOTE_OPEN + QUOTE_CLOSE + '\n';
    let l = start;
    while (l > 0 && !leftMarks.includes(text[l - 1])) l--;
    let r = end;
    while (r < text.length && !rightStops.includes(text[r])) r++;
    if (r < text.length && stopMarks.includes(text[r])) r++; // 句末标点收进来，引号星号留在外面
    return text.slice(l, r).trim();
  }

  function expandToClause(text, start, end) {
    const s = String(text || '');
    const leftMarks = '\n。！？!?，,；;：:' + QUOTE_OPEN + QUOTE_CLOSE;
    const punctMarks = '。！？!?，,；;：:';
    const rightStops = punctMarks + QUOTE_OPEN + QUOTE_CLOSE + '\n';
    let l = Math.max(0, start);
    while (l > 0 && !leftMarks.includes(s[l - 1])) l--;
    let r = Math.min(s.length, end);
    while (r < s.length && !rightStops.includes(s[r])) r++;
    // 只把标点收进来；引号、星号等标记符号永远留在单元外。
    if (r < s.length && punctMarks.includes(s[r])) r++;
    let unit = s.slice(l, r).trim();
    // 分句过短时，回退到完整句；避免“肋骨，”这种没法独立改的残片。
    const bare = unit.replace(/[\s，,；;：:。！？!?]+/g, '');
    if (bare.length < 4) return expandToSentence(s, start, end);
    return unit;
  }

  function expandToPurifyUnit(text, start, end, mode) {
    return mode === 'sentence' ? expandToSentence(text, start, end) : expandToClause(text, start, end);
  }

  const CLAUSE_LEVEL_PATTERN_LABELS = new Set([
    '数字精确量','短句碎片','形容词尾巴碎片','叙述重量-方式腔','动作后注释','解脱标记','情绪标签式对话','无功能呼吸叹气','比喻性情态状语'
  ]);

  function collectPatternSentences(text, labels) {
    const out = [];
    getAllPatternRules().filter(p => labels.includes(p.label)).forEach(p => {
      const re = cloneRegexGlobal(p.re);
      const mode = CLAUSE_LEVEL_PATTERN_LABELS.has(p.label) ? 'clause' : 'sentence';
      let m;
      while ((m = re.exec(text))) {
        const sent = expandToPurifyUnit(text, m.index, m.index + m[0].length, mode);
        if (sent && !out.includes(sent)) out.push(sent);
        if (m[0].length === 0) re.lastIndex++;
      }
    });
    return out;
  }


