  async function persistPurifiedMessage(target, mesEl, newText) {
    target.chat[target.idx].mes = newText;
    const ctx = target.ctx || ROOT.SillyTavern?.getContext?.();
    const msg = target.chat[target.idx];
    const refreshFns = [
      ctx?.updateMessageBlock,
      ROOT.updateMessageBlock
    ].filter(fn => typeof fn === 'function');
    for (const fn of refreshFns) {
      try { await Promise.resolve(fn.call(ctx || ROOT, target.idx, msg, { rerenderMessage:true })); break; }
      catch(e) { console.warn('[Orpheus purify] updateMessageBlock:', e); }
    }
    try {
      const es = ctx?.eventSource || ROOT.eventSource;
      const et = ctx?.event_types || ROOT.event_types;
      if (es?.emit && et) {
        // 1) 数据更新事件
        const updEv = et.MESSAGE_UPDATED || et.MESSAGE_EDITED || et.CHAT_CHANGED;
        if (updEv) await Promise.resolve(es.emit(updEv, target.idx));
        // 2) 补发"消息渲染完成"事件：叫醒酒馆助手等扩展，重新把 ```html 渲染成卡片
        //    否则净化重建 DOM 后代码块会停在原生折叠态
        const isUser = !!target.chat[target.idx]?.is_user;
        const renderEv = isUser ? et.USER_MESSAGE_RENDERED : et.CHARACTER_MESSAGE_RENDERED;
        if (renderEv) await Promise.resolve(es.emit(renderEv, target.idx));
      }
    } catch(e) {}
    try {
      if(typeof ROOT.saveChatConditional === 'function') await Promise.resolve(ROOT.saveChatConditional());
      else if(typeof ctx?.saveChatConditional === 'function') await Promise.resolve(ctx.saveChatConditional());
      else if(typeof ctx?.saveChat === 'function') await Promise.resolve(ctx.saveChat());
