  // ─── 净化 AI：只替换检测到的词/句，逐词打点 ──────────────────

  function collectWordContextSentences(text, word, limit) {
    const s = String(text || '');
    const w = String(word || '');
    const out = [];
    if(!s || !w) return out;
    let from = 0;
    const max = limit || 6;
    while (from < s.length && out.length < max) {
      const idx = s.indexOf(w, from);
      if(idx < 0) break;
      const sent = expandToSentence(s, idx, idx + w.length) || w;
      if(sent && !out.includes(sent)) out.push(sent);
      from = idx + Math.max(1, w.length);
    }
    return out;
  }

  function collectWordHitUnits(text, word, limit) {
    const s = String(text || '');
    const w = String(word || '');
    const out = [];
    if(!s || !w) return out;
    let from = 0;
    const max = limit || 6;
    while (from < s.length && out.length < max) {
      const idx = s.indexOf(w, from);
      if(idx < 0) break;
      const unit = expandToClause(s, idx, idx + w.length) || w;
      if(unit && !out.includes(unit)) out.push(unit);
      from = idx + Math.max(1, w.length);
    }
    return out;
  }

  function buildPurifyHitItems(text, found) {
    const hits = [];
    const byId = new Map();
    const add = item => {
      if(!item?.key) return;
      // v5.4.5：净化改为“最小分句级”。词条只负责检测，真正写回时只替换命中词所在分句，
      // 避免长句/整段被 AI 过度清洗，导致文风和上下文割裂。
      const type = 'sentence';
      const key = String(item.key || '').trim();
      if(!key) return;
      const id = type + '::' + key;
      const label = String(item.label || '').trim();
      const instruction = String(item.instruction || '').trim();
      const contexts = Array.isArray(item.contexts) ? item.contexts.filter(Boolean) : [];
      const old = byId.get(id);
      if(old){
        if(label && !old.labels.includes(label)) old.labels.push(label);
        if(instruction && !old.instructions.includes(instruction)) old.instructions.push(instruction);
        contexts.forEach(ctx => { if(ctx && !old.contexts.includes(ctx)) old.contexts.push(ctx); });
        old.label = old.labels.join(' + ');
        old.instruction = old.instructions.join('\n');
        return;
      }
      const fresh = Object.assign({}, item, {
        type,
        key,
        labels: label ? [label] : [],
        instructions: instruction ? [instruction] : [],
        contexts,
      });
      fresh.label = fresh.labels.join(' + ');
      fresh.instruction = fresh.instructions.join('\n');
      byId.set(id, fresh);
      hits.push(fresh);
    };

    const addSentenceHit = (sent, label, instruction, hitWord, sourceType) => {
      sent = String(sent || '').trim();
      if(!sent) return;
      const typeNote = sourceType === 'anatomy'
        ? '这是医学/解剖/专业词命中；仅在非医疗、非专业语境里，把命中词改成更日常的部位、体感或动作表达。'
        : '这是八股词/AI味词命中；只处理命中词所在分句，必要时只做分句内最小补缝。';
      add({
        type:'sentence',
        key:sent,
        label,
        contexts:[],
        instruction:[
          hitWord ? ('命中词：' + hitWord + '。') : '',
          typeNote,
          instruction || ''
        ].filter(Boolean).join('\n')
      });
    };

    // v5.4.5：词条命中升级为“所在最小分句”key，value 返回同一分句的最小改写。
    // 自定义通配词（如 xx骨 / xx椎）会先解析成实际词（腕骨、腰椎等），再定位到所在句。
    const wordMatches = getPurifyWordMatches(text).filter(item => found.includes(item.word));
    wordMatches.forEach(item => {
      const type = item.type === 'anatomy' ? 'anatomy' : 'word';
      const labelBase = type === 'anatomy' ? '解剖/专业词' : '八股词';
      const instruction = item.instruction || getWordInstruction(item.word, type);
      const units = collectWordHitUnits(text, item.word, 8);
      const sentences = units.length ? units : [purifySentenceAround(text, item.word)];
      sentences.filter(Boolean).forEach(sent => {
        addSentenceHit(sent, labelBase + '：' + item.word, instruction, item.word, type);
      });
    });

    // 句式命中：本来就是完整句，继续保持句子级最小改写。
    const patHits  = found.filter(f => f.startsWith('【')).map(f => f.slice(1,-1));
    patHits.forEach(label => {
      collectPatternSentences(text, [label]).forEach(sent => {
        add({type:'sentence', key:sent, label:'句式：' + label, instruction:getPatternInstruction(label)});
      });
    });
    return hits;
  }

  function purifySentenceAround(text, key){
    const s = String(text || '');
    const idx = s.indexOf(key);
    if(idx < 0) return '';
    return expandToSentence(s, idx, idx + String(key || '').length);
  }

  async function callPurifyAi(text, found) {
    const hitItems = buildPurifyHitItems(text, found);
    if (!hitItems.length) return null;

    const sys = getPurifySystemPrompt();
    const styleGuide = buildPurifyStyleGuide(text, hitItems);
    const selectedModel = resolveAiModel(cfg.aiBaseUrl,cfg.aiModel);
    const isQwen = isQwenThinkingModel(selectedModel);
    const itemLines = hitItems.map((item, i) => {
      const hardRule = [
        'hard_limit: key 是待净化的原文单位，通常只是一个分句；value 必须只改写这一个 key。',
        '只处理 label / rule 指向的问题词或句式；key 内没有问题的信息、动作、人物、顺序尽量原样保留。',
        '禁止把 key 当成灵感重写，禁止清洗整段，禁止替换 key 外的上下文。',
        '若只替换/删除命中词会让分句不通，允许在命中词前后很小范围顺句；但禁止把原句改成全新表达。',
        '风格必须贴合 style_hint / style_sample，但风格只用于对齐语气，不得借机润色无关内容。',
        '符号铁律：严禁增、删、移动或改变任何成对符号——包括直双引号、直单引号、中文弯引号「」『』《》、全角与半角圆括号、方括号、反引号、星号（对话/心声/强调标记）。key 抓到什么符号、在什么位置，value 必须原样保留，一个都不许多、不许少、不许换形态（例如不许把直引号改成弯引号）。',
        '禁止 value 等于 key；没有有效改写就不要输出这个 key。',
        '只有当 key 完全是无功能废句/碎片时，value 才可以是空字符串。',
        '解剖/医学词改写不得造词，不得新增原文没有的身体部位；宁可少改，也不要写出“颧头/颧弧/下颌线绷成弧度”这类怪句。'
      ].join(' ');
      return [
        `${i+1}. type: sentence_or_clause`,
        `label: ${item.label}`,
        `key: ${JSON.stringify(item.key)}`,
        hardRule,
        `rule: ${item.instruction}`
      ].filter(Boolean).join('\n');
    }).join('\n\n');
    const styleBlock = styleGuide ? ('\n\n【风格锚定】\n' + styleGuide + '\n') : '';
    const userMsg = (isQwen ? '/no_think\n' : '') + '按每条 rule 改写对应 key。只输出 JSON，不要解释；没有列出的 key 绝对不要输出。key 是原文最小单位，value 必须返回同一单位的最小改写；不要返回短词替换，不要改写整段。禁止让 value 等于 key；无法有效改写的条目不要输出。' + styleBlock + '\n\n' + itemLines;
    const messages = isQwen
      ? [{role:'user',content:sys + '\n\n' + userMsg}]
      : [{role:'system',content:sys},{role:'user',content:userMsg}];
    let result = await callAI(messages, null, null, null, null, {jsonMode:true,disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    if(!result && /^empty_response/.test(lastAiError)){
      const compact = '立即输出 JSON，不要思考，不要解释。key 是原文最小单位；value 是同一单位的最小改写。只修命中问题，不要整段润色；不要让 value 等于 key；无法有效改写就省略该 key：\n' + hitItems.map(x => JSON.stringify(x.key) + ' // ' + x.label + ' // ' + x.instruction).join('\n');
      result = await callAI(isQwen ? [{role:'user',content:'/no_think\n' + compact}] : [{role:'system',content:sys},{role:'user',content:compact}], null, null, null, null, {disableThinking:true,omitTokenLimit:true,relaxed:true,acceptReasoningJson:true});
    }
    return result;
  }


  const SAFE_ANATOMY_REPLACEMENTS = {
    '颧骨':'脸颊', '肋骨':'腰侧', '锁骨':'颈侧', '肩胛':'肩背', '肩胛骨':'肩背',
    '腰椎':'后腰', '颈椎':'后颈', '胸椎':'背心', '尾椎':'尾骨处',
    '胯骨':'胯侧', '髋骨':'胯侧', '耻骨':'小腹', '骨节':'手指', '脊背':'后背', '背脊':'后背',
    '喉结':'喉间', '脉搏':'心跳', '鼓膜':'耳膜', '虹膜':'眼睛',
    '血管':'青筋', '动脉':'血脉', '静脉':'青筋', '神经':'感官', '淋巴':'颈侧'
  };

  const BAD_ANATOMY_REWRITE_RE = /(颧头|颧弧|颧侧|颧面|颧部|颧峰|颧线|骨线|骨面|骨弧|肋线|肋面|锁骨线|脊线|胯线|髋线|耻骨线|下颌线绷成的?弧度|绷成的?弧度)/;
  const NEW_ANATOMY_TERMS = ['下颌线','下颌','颧头','颧弧','颧侧','颧面','颧部','颧峰','颧线','骨线','骨面','骨弧','肋线','肋面','锁骨线','脊线','胯线','髋线','耻骨线'];

  function getHitWordFromItem(item){
    const info = String((item?.label || '') + '\n' + (item?.instruction || ''));
    const m = info.match(/命中词：([^。\n]+)[。\n]?/);
    if(m && m[1]) return m[1].trim();
    const m2 = info.match(/(?:八股词|解剖\/专业词)：([^\n]+)/);
    if(m2 && m2[1]) return m2[1].trim();
    return '';
  }

  function buildSafeAnatomyFallback(realKey, item){
    const hit = getHitWordFromItem(item);
    const source = String(realKey || '');
    const tryWords = hit ? [hit] : [];
    Object.keys(SAFE_ANATOMY_REPLACEMENTS).forEach(w => { if(source.includes(w) && !tryWords.includes(w)) tryWords.push(w); });
    let next = source;
    tryWords.forEach(w => {
      const repl = SAFE_ANATOMY_REPLACEMENTS[w];
      if(w && repl) next = next.split(w).join(repl);
    });
    return next !== source ? next : '';
  }

  function looksLikeAnatomyItem(item){
    const info = String((item?.label || '') + '\n' + (item?.instruction || ''));
    return /解剖|医学|专业词|anatomy|颧骨|肋骨|锁骨|肩胛|腰椎|颈椎|胸椎|尾椎|胯骨|髋骨|耻骨|喉结|脉搏|鼓膜|虹膜/.test(info);
  }

  function validatePurifyValue(realKey, val, item){
    const original = String(realKey || '');
    let value = String(val || '').trim();
    if(!looksLikeAnatomyItem(item)) return {ok:true, val:value};

    // 1) 明确怪词直接判坏。
    if(BAD_ANATOMY_REWRITE_RE.test(value)){
      const fb = buildSafeAnatomyFallback(original, item);
      return fb ? {ok:true, val:fb.trim()} : {ok:false, val:''};
    }

    // 2) 解剖词净化不允许新增原文没有的身体部位/审美线条。
    for(const term of NEW_ANATOMY_TERMS){
      if(value.includes(term) && !original.includes(term)){
        const fb = buildSafeAnatomyFallback(original, item);
        return fb ? {ok:true, val:fb.trim()} : {ok:false, val:''};
      }
    }

    // 3) 特例：命中“颧骨”时，输出里仍含“颧”字，通常就是半医学半造词，回退到“脸颊”。
    const hit = getHitWordFromItem(item);
    if((hit === '颧骨' || original.includes('颧骨')) && /颧/.test(value)){
      const fb = buildSafeAnatomyFallback(original, item);
      return fb ? {ok:true, val:fb.trim()} : {ok:false, val:''};
    }

    return {ok:true, val:value};
  }

  function filterPurifyMap(rawMap, text, found) {
    const map = normalizePurifyMap(rawMap);
    const hitItems = buildPurifyHitItems(text, found);
    const byKey = new Map(hitItems.map(item => [item.key, item]));
    const out = {};
    Object.entries(map).forEach(([key, value]) => {
      const k = String(key || '');
      const item = byKey.get(k) || byKey.get(k.trim());
      if(!item) return;
      const realKey = item.key;
      if(!String(text || '').includes(realKey)) return;
      const rawVal = value == null ? '' : String(value);
      const val = rawVal.trim();
      const info = String((item.label || '') + '\n' + (item.instruction || ''));
      const allowDelete = /无功能呼吸叹气|整句完全是无功能废句/.test(info)
        || /^(?:深吸一口气|轻叹一声|舔了舔嘴唇)[。！？!?]?$/.test(realKey.trim());

      // 防止“AI 原样返回”造成假成功。
      if(rawVal === realKey || val === realKey.trim()) return;

      // 句子级净化允许整句删除，但只在规则明显允许删除时放行。
      if(!val){
        if(allowDelete) out[realKey] = '';
        return;
      }

      const checked = validatePurifyValue(realKey, val, item);
      if(!checked.ok) return;
      const safeVal = String(checked.val || '').trim();
      if(!safeVal){
        if(allowDelete) out[realKey] = '';
        return;
      }

      // 对话/心声标记保护：value 里出现了 key 没有的引号、星号等符号，一律丢弃，防止AI补符号弄乱原文。
      const MARK_CHARS = ['\u201c','\u201d','\u2018','\u2019','\u0022','\u0027','\u300c','\u300d','\u300e','\u300f','\u300a','\u300b','\uff08','\uff09','(',')','[',']','*','`'];
      for(const mc of MARK_CHARS){
        const cIn = (safeVal.split(mc).length - 1), cKey = (realKey.split(mc).length - 1);
        if(cIn !== cKey) return; // 符号数量必须完全一致：多一个少一个都丢弃
      }

      // 分句级 value 不能离谱扩写，也不能把原句整段包进去。
      if(safeVal.length > Math.max(realKey.length * 1.75, realKey.length + 60)) return;
      if(realKey.length > 20 && safeVal.length < Math.max(4, realKey.length * 0.20) && !allowDelete) return;
      if(safeVal.includes(realKey) && safeVal.length > realKey.length + 4) return;

      out[realKey] = safeVal;
    });
    return Object.keys(out).length ? out : null;
  }

  function buildLocalPurifyFallback(text, found) {
    // v5.1 起净化规则改为“检测项 + 修改指令”，不再做本地机械直替。
    // 没有可用 AI 时只展示命中项和内置/自定义规则，避免误报“已注入”。
    return null;
  }

  // ─── 解析 AI 返回的 JSON 映射 ────────────────────────────────

  function parseWordMap(mapJson) {
    if (!mapJson) return null;
    let clean = String(mapJson).replace(new RegExp('\\x60{3}json|\\x60{3}','g'),'').trim();
    // 兼容模型在 JSON 前后附加说明文字的情况（如 Deepseek）
    const m = clean.match(/\{[\s\S]*\}/);
    if (m) clean = m[0];
    // 1) 标准解析
    try { return normalizePurifyMap(JSON.parse(clean)); } catch(e) {}
    // 2) 容错：模型常把英文引号/冒号/逗号写成中文标点，导致 JSON 非法
    try {
      const fixed = clean
        .replace(/[\u201c\u201d\u2018\u2019]/g, '"')
        .replace(/\uff1a/g, ':')
        .replace(/\uff0c/g, ',')
        .replace(/,\s*}/g, '}')
        .replace(/,\s*]/g, ']');
      return normalizePurifyMap(JSON.parse(fixed));
    } catch(e) {}
    // 3) 逐键值对正则兜底：容忍 value 内未转义的双引号
    try {
      const out = {};
      const re = /"((?:[^"\\]|\\.)*?)"\s*:\s*"([\s\S]*?)"(?=\s*[,}])/g;
      let mm;
      while ((mm = re.exec(clean)) !== null) { if (mm[1]) out[mm[1]] = mm[2]; }
      if (Object.keys(out).length) return normalizePurifyMap(out);
    } catch(e) {}
    return null;
  }
  // 把 map 应用到纯文本（用于预览）

  // ── 符号守恒保险丝 ─────────────────────────────────────────
  // 引号/星号/书名号等标记符号在任何改写前后必须数量守恒；
  // 只要变了一个，本段改写整体作废，宁可不洗也不吃符号。
  const GUARD_MARKS = ['\u201c','\u201d','\u2018','\u2019','\u0022','\u0027','\u300c','\u300d','\u300e','\u300f','\u300a','\u300b','\uff08','\uff09','(',')','[',']','*','`'];
  let symbolGuardBlocked = 0;
  function symbolsBroken(before, after){
    for(const mc of GUARD_MARKS){
      if((String(before).split(mc).length) !== (String(after).split(mc).length)) return true;
    }
    return false;
  }
  // 配对合法性：引号方向、星号成对。返回 true 表示配对已破。
  function quotePairingBroken(text){
    const s = String(text || '');
    const pairs = [['\u201c','\u201d'],['\u300c','\u300d'],['\u300e','\u300f'],['\u300a','\u300b'],['\uff08','\uff09'],['(',')'],['[',']']];
    for(const [open, close] of pairs){
      let depth = 0;
      for(const ch of s){
        if(ch === open) depth++;
        else if(ch === close){ depth--; if(depth < 0) return true; }
      }
      if(depth !== 0) return true;
    }
    // 非方向性成对符号（直双引号/直单引号/反引号）必须成对出现
    for(const ch of ['\u0022','\u0027','`']){
      if(((s.split(ch).length - 1) % 2) !== 0) return true;
    }
    // 星号：**（强调）须成对，剩余 *（动作/心声）也须成对
    const dblStar = (s.match(/\*\*/g) || []).length;
    const totalStar = (s.match(/\*/g) || []).length;
    const singleStar = totalStar - dblStar * 2;
    if((dblStar % 2) !== 0 || (singleStar % 2) !== 0) return true;
    return false;
  }
  function guardedApplyMap(text, map){
    const next = applyMapToText(text, map);
    if(next === text) return next;
    // 第一道：符号数量守恒
    if(symbolsBroken(text, next)){
      symbolGuardBlocked++;
      console.warn('[Orpheus🛡️] 拦截：改写改变了符号数量', {改写前: text, 改写后: next, map});
      return text;
    }
    // 第二道：配对由好变坏（数量没变但位置/方向乱了）也拦
    if(!quotePairingBroken(text) && quotePairingBroken(next)){
      symbolGuardBlocked++;
      console.warn('[Orpheus🛡️] 拦截：改写打乱了引号/星号配对', {改写前: text, 改写后: next, map});
      return text;
    }
    return next;
  }

  function applyMapToText(text, map) {
    const normalized = normalizePurifyMap(map);
    const sorted = Object.entries(normalized)
      .sort((a,b) => b[0].length - a[0].length)
      .filter(([orig]) => orig);
    if (!sorted.length) return text;
    // 按 HTML 标签切割，只替换标签外的文本节点，保护 HTML 属性和类名
    const parts = text.split(/(<[^>]*>)/);
    return parts.map((part, i) => {
      if (i % 2 === 1) return part; // HTML 标签内，跳过
      let t = part;
      sorted.forEach(([orig, repl]) => { t = t.split(orig).join(repl || ''); });
      return t;
    }).join('');
  }


  function findContextRangesInVisibleText(visible, raw) {
    const parts = getContextParts(raw);
    if (!parts.length) return [{ start: 0, end: visible.length }];
    const ranges = [];
    let from = 0;
    parts.forEach(part => {
      const candidates = [part, part.trim()].filter(Boolean);
      for (const cand of candidates) {
        const start = visible.indexOf(cand, from);
        if (start >= 0) {
          ranges.push({ start, end: start + cand.length });
          from = start + cand.length;
          break;
        }
      }
    });
    return ranges;
  }

  function applyMapToDomContext(textEl, map, raw) {
    const walker = DOC.createTreeWalker(textEl, 4); // NodeFilter.SHOW_TEXT = 4
    const nodes = [];
    let visible = '';
    let tn;
    while(tn = walker.nextNode()) {
      const start = visible.length;
      visible += tn.textContent || '';
      nodes.push({ node: tn, start, end: visible.length });
    }
    const ranges = findContextRangesInVisibleText(visible, raw);
    if (!ranges.length) return false;
    nodes.forEach(item => {
      let changed = false;
      let cursor = 0;
      let next = '';
      ranges.forEach(range => {
        const s = Math.max(range.start, item.start) - item.start;
        const e = Math.min(range.end, item.end) - item.start;
        if (s >= e) return;
        next += item.node.textContent.slice(cursor, s);
        next += guardedApplyMap(item.node.textContent.slice(s, e), map);
        cursor = e;
        changed = true;
      });
      if (changed) {
        next += item.node.textContent.slice(cursor);
        item.node.textContent = next;
      }
    });
    return true;
  }

