  function updatePurifyArea(){
    const area=DOC.getElementById('cc-purify-area'); if(!area)return;
    if(!lastPurify||!lastPurify.found?.length){area.style.display='none';$pbadge.classList.remove('has-count');return;}
    const {found}=lastPurify;
    area.style.display='';
    area.className='cc-purify-wrap';
    area.innerHTML=`
      <div class="cc-sec-hd" style="padding-top:9px;">
        <span class="cc-sec-lbl">🔍 净化检测 · ${found.length}处</span>
        <span class="cc-sec-act" id="cc-purify-clr">清除</span>
      </div>
      <div class="cc-ptags">${found.map(f=>`<span class="cc-ptag">${esc(f)}</span>`).join('')}</div>
      ${quotePairingBroken(lastPurify.text)?`<div style="font-size:10.5px;color:#c0392b;background:rgba(192,57,43,.08);border:1px solid rgba(192,57,43,.25);border-radius:8px;margin:4px 14px 6px;padding:6px 9px;line-height:1.5;">⚠️ 符号体检：本楼引号/星号配对不完整（开闭不匹配）。多半是历史楼层损坏残留——建议手动补好，否则写作模型会模仿坏符号，新楼越生成越乱。净化不会碰这些符号。</div>`:''}
      <div style="font-size:10px;color:var(--txt3);line-height:1.55;padding:0 14px 5px;">提示：词条和句式只作为 AI 改写规则，命中词按所在最小分句改写；会参考当前文风预设，避免整段清洗。</div>
      ${purifyCleanText?`<div class="cc-pclean" id="cc-pclean-view"><b style="font-size:10px;color:var(--txt3)">净化结果：</b><br>${esc(purifyCleanText).replace(/\n/g,'<br>')}</div>`:''}
      <div class="cc-pbtns">
        <button class="cc-pb-ai" id="cc-purify-ai-btn">🤖 AI净化</button>
        <button class="cc-pb-apply ${purifyCleanText?'show':''}" id="cc-purify-apply-btn">✓ 应用到正文</button>
        <button id="cc-purify-orig-btn">查看原文</button>
