      purifyBusy=true;
      const b=DOC.getElementById('cc-purify-apply-btn'); if(b){b.disabled=true;b.textContent='写入中…';}
      try{ await applyToChat(lastPurifyMap); }finally{ ccSetTimeout(()=>{purifyBusy=false;},800); }
    };
    DOC.getElementById('cc-purify-orig-btn').onclick=()=>{
