        area.insertBefore(d,area.querySelector('.cc-pbtns'));
      } else { pclean.innerHTML=`<b style="font-size:10px;color:var(--txt3)">原文（高亮标注）：</b><br>${hlForbidden(lastPurify.text,lastPurify.found)}`; }
    };
