  let lastPurifyMap = null; // 存储最近一次解析好的替换映射
  function getAutoPurifyMaxRounds(){
    const n = parseInt(cfg.autoFixMaxRounds, 10);
    return Math.min(10, Math.max(1, Number.isFinite(n) ? n : 1));
  }

  function rescanPurifyTarget(idx, fallbackMesEl){
    const target = getTargetMessageByIndex(idx) || (fallbackMesEl ? getTargetMessageFromEl(fallbackMesEl) : null);
    const text = target ? getPurifyTextFromRaw(target.raw) : '';
    if(!target || !text) return {ok:false, reason:'no-context'};
    const found = scanForbidden(text);
    if(!found.length){
      lastPurify=null; lastPurifyMap=null; purifyCleanText='';
      updatePurifyArea();
      try { $pbadge.classList.remove('has-count'); } catch(e) {}
      return {ok:true, clean:true, target, text, found};
    }
    lastPurify={text,found,mesEl:target.mesEl || fallbackMesEl,idx:target.idx};
    lastPurifyMap=null;
    purifyCleanText='';
    updatePurifyArea();
    return {ok:true, clean:false, target, text, found};
  }




  async function runAiPurify(){
    if(!lastPurify?.found?.length){showBubble('暂无检测数据');return;}
    if(purifyBusy){showBubble('净化进行中，请稍等…');return;}
    const fresh = rescanPurifyTarget(lastPurify.idx, lastPurify.mesEl);
    if(fresh.ok && fresh.clean){ showBubble('✓ 当前 context 已无启用中的净化项'); return; }
    if(!lastPurify?.found?.length){ showBubble('暂无启用中的检测数据'); return; }
    purifyBusy = true;
    const btn=DOC.getElementById('cc-purify-ai-btn'); if(btn){btn.textContent='净化中…';btn.disabled=true;}
    showBubble('🔧 后台净化中；结果会保留在「预设」净化区，未写入前不会提示已注入。', 15000);
    let map = null, usedFallback = false, parseFailed = false, invalidMap = false;
    try {
    if(cfg.purifyAiEnabled !== false && cfg.openaiKey){
      const mapJson=await callPurifyAi(lastPurify.text,lastPurify.found);
      if(mapJson){
        const parsed = parseWordMap(mapJson);
        parseFailed = !parsed;
        if(parsed){
          map=filterPurifyMap(parsed, lastPurify.text, lastPurify.found);
          invalidMap = !map;
        }
      }
    }
    if(!map){
      map = buildLocalPurifyFallback(lastPurify.text,lastPurify.found);
      usedFallback = !!map;
    }
    // 净化完成，更新UI（无论当前在哪个Tab）
    const btnAfter=DOC.getElementById('cc-purify-ai-btn'); if(btnAfter){btnAfter.textContent='🤖 AI净化';btnAfter.disabled=false;}
    if(map){
      lastPurifyMap=map;
      purifyCleanText=applyMapToText(lastPurify.text,map);
      updatePurifyArea();
      showBubble('✓ AI净化完成，待你确认应用到正文');
    } else if(parseFailed) showBubble('净化结果解析失败' + (lastAiError ? '：'+lastAiError : '，模型返回了非JSON内容'));
    else if(invalidMap) showBubble('AI 返回了 JSON，但没有有效改写；可能是原样返回或改动过大，已丢弃');
    else if(!cfg.openaiKey) showBubble('请先在「⚙️ 设置」填写 API Key；v5.1 不再做本地机械直替');
    else showBubble('净化请求失败：' + (lastAiError || '检查 API Key / URL / 模型'));
    } finally {
      ccSetTimeout(()=>{ purifyBusy=false; }, 800);
    }
  }


  async function autoRunPurify(){
    if(purifyBusy) return;
    if(!lastPurify?.found?.length) return;
    const fresh = rescanPurifyTarget(lastPurify.idx, lastPurify.mesEl);
    if(fresh.ok && fresh.clean) return;
    if(!lastPurify?.found?.length) return;
    purifyBusy = true;
    const maxRounds = getAutoPurifyMaxRounds();
    let round = 0, totalHits = 0, lastRoundHits = 0;
    try {
      while(lastPurify?.found?.length && round < maxRounds){
        round++;
        const cnt0 = lastPurify.found.length;
        lastRoundHits = cnt0;
        totalHits += cnt0;
        const targetIdx = lastPurify.idx;
        const targetMesEl = lastPurify.mesEl || getMesElByIndex(targetIdx);

        let map = null;
        if(cfg.purifyAiEnabled !== false && cfg.openaiKey){
          const mapJson = await callPurifyAi(lastPurify.text, lastPurify.found);
          if(mapJson){ map = filterPurifyMap(parseWordMap(mapJson), lastPurify.text, lastPurify.found); }
        }
        if(!map) map = buildLocalPurifyFallback(lastPurify.text, lastPurify.found);

        if(!map){
          showBubble('⚠️ 捕获到八股词/句式 '+cnt0+' 处；没有可用 AI，未自动改写，已保留手动净化入口', 7000);
          if(drawerOpen && activeTab !== 'preset') switchTab('preset');
          return;
        }

        lastPurifyMap = map;
        purifyCleanText = applyMapToText(lastPurify.text, map);
        updatePurifyArea();
        symbolGuardBlocked = 0;
        const ok = await applyToChat(map, {quiet:true});
        if(symbolGuardBlocked > 0) showBubble('🛡️ 有 ' + symbolGuardBlocked + ' 段改写因引号/星号数量变化被拦截，原文未动', 7000);
        if(ok !== true){
          showBubble('⚠️ 自动净化生成了建议，但没有让当前 <context> 发生变化，已保留在净化区', 8000);
          return;
        }

        const next = rescanPurifyTarget(targetIdx, targetMesEl);
        if(!next.ok){
          showBubble('✓ 自动净化已写入，但未能重新读取 <context>；可手动再扫一次确认', 7000);
          return;
        }
        if(next.clean){
          showBubble('✓ 自动净化完成，已循环校验到无命中（'+round+'轮，共处理 '+totalHits+' 处）', 7000);
          return;
        }
        showBubble('↻ 第 '+round+' 轮写回后又命中 '+next.found.length+' 处，继续自动净化…', 5000);
        await new Promise(resolve => ccSetTimeout(resolve, 180));
      }

      if(lastPurify?.found?.length){
        showBubble('⚠️ 自动净化已连续跑 '+maxRounds+' 轮，仍命中 '+lastPurify.found.length+' 处。为避免死循环已暂停，结果保留在净化区，可手动处理。', 9000);
        if(drawerOpen && activeTab !== 'preset') switchTab('preset');
      }
    } finally {
      ccSetTimeout(()=>{ purifyBusy=false; }, 800);
    }
  }

  // ── 预设分组：改进版 ────────────────────────────────────────
  // 优先读取 ST 原生分类结构，其次用分隔符推断，支持自动检测分隔符
  function autoDetectSep(names) {
    // 统计常见分隔符在名字里出现的频次，取最多的
    const cands = ['/', '-', '_', '·', '|', ':'];
    let best = cfg.groupSeparator || '/';
    let bestCount = 0;
    for (const c of cands) {
      const cnt = names.filter(n => n.includes(c)).length;
      if (cnt > bestCount) { bestCount = cnt; best = c; }
    }
    // 至少 30% 的条目有这个分隔符才认为是分组符
    return bestCount >= Math.max(2, names.length * 0.3) ? best : null;
  }

  function scanAndRenderPreset(container) {
    // ① 尝试 ST prompt manager 列表
    const list = DOC.querySelector('#completion_prompt_manager_list');
    if (!list) {
      container.innerHTML='<div class="cc-no-entry">⚠️ 未检测到预设面板<br>请先点开酒馆预设区域，再点「↻ 扫描」</div>';
      return;
    }

    // ② 收集所有条目（含 injection_position 等各种类型）
    const items = [...list.querySelectorAll('li[data-pm-identifier]')];
    if (!items.length) {
      container.innerHTML='<div class="cc-no-entry">暂无预设条目</div>';
      return;
    }

    // ③ 解析名字 + 启用状态，同时兼容多种 ST 版本 DOM
    const parsed = items.map(li => {
      // 名字：优先 data-pm-name，其次 .prompt-manager-prompt-name，其次 textContent
      const nameEl = li.querySelector('[data-pm-name]')
                  || li.querySelector('.prompt-manager-prompt-name')
                  || li.querySelector('[title]');
      const name = (nameEl?.getAttribute?.('data-pm-name')
                 || nameEl?.getAttribute?.('title')
                 || nameEl?.textContent
                 || li.textContent).trim().replace(/\s+/g,' ');
      // 启用状态：disabled class / aria-checked / toggle button state
      const disabled = li.classList.contains('completion_prompt_manager_prompt_disabled')
                    || li.classList.contains('disabled')
                    || li.querySelector('.prompt-manager-toggle-action')?.getAttribute('aria-checked')==='false';
      return { name, li, on: !disabled };
    }).filter(e => e.name);

    // ④ 决定分隔符
    const names = parsed.map(e => e.name);
    const sep = (cfg.groupSeparator && cfg.groupSeparator !== '/')
              ? cfg.groupSeparator
              : (autoDetectSep(names) || '/');

    // ⑤ 分组：按截图指定的预设板块硬分类，避免关键词误伤或漏项。
