    const activeAnatomyCount = FORB_ANATOMY.filter(w => !isBuiltinWordDisabled(w)).length;

    const builtinPatterns = Object.keys(PATTERN_INSTRUCTIONS).map(label => {
      const disabled = isBuiltinPatternDisabled(label);
      return `
      <div class="cc-rule-card" data-bpcard="${esc(label)}" style="${disabled?'opacity:.58;':''}">
        <div class="cc-rule-title">
          <span>句式 · ${esc(label)}${disabled?'（已停用）':''}</span>
          <span><button class="cc-mini-btn" data-bpedit="${esc(label)}">保存</button><button class="cc-mini-btn" data-bpreset="${esc(label)}">还原</button><button class="cc-mini-btn ${disabled?'':'danger'}" data-bptoggle="${esc(label)}">${disabled?'启用':'停用'}</button></span>
        </div>
        <textarea class="cc-rule-textarea" data-bpinst="${esc(label)}">${esc(getPatternInstruction(label))}</textarea>
      </div>`;
    }).join('');

    const customWords = customPurifyWords.length ? customPurifyWords.map((item, idx) => `
      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>${item.type==='anatomy'?'医学/专业词':'八股词'} · ${esc(item.word)}</span><button class="cc-mini-btn danger" data-cwdel="${idx}">删除</button></div>
      </div>`).join('') : '<div class="cc-no-entry">暂无自定义词条</div>';

    const customPatterns = customPurifyPatterns.length ? customPurifyPatterns.map((item, idx) => `
      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>句式 · ${esc(item.label)}</span><button class="cc-mini-btn danger" data-cpdel="${idx}">删除</button></div>
        <div style="font-size:10px;color:var(--txt3);margin-bottom:4px;">/${esc(item.pattern)}/${esc(item.flags || '')}</div>
        <div>${esc(item.instruction || '')}</div>
      </div>`).join('') : '<div class="cc-no-entry">暂无自定义句式</div>';

    pane.innerHTML=`
      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>AI 总提示词</span><span><button class="cc-mini-btn" id="ss-sys-save">保存</button><button class="cc-mini-btn" id="ss-sys-reset">还原默认</button></span></div>
        <textarea class="cc-rule-textarea" id="ss-sys-prompt" style="min-height:145px;">${esc(getPurifySystemPrompt())}</textarea>
      </div>

      <div class="cc-rule-card">
        <div class="cc-rule-title"><span>分类修改规则</span><span><button class="cc-mini-btn" id="ss-cat-save">保存</button><button class="cc-mini-btn" id="ss-cat-reset">还原默认</button></span></div>
        <div class="cc-slabel" style="padding:0;margin:0 0 4px;">八股词这一类怎么改</div>
        <textarea class="cc-rule-textarea" id="ss-word-rule" style="min-height:84px;">${esc(getCategoryRule('word'))}</textarea>
        <div class="cc-slabel" style="padding:8px 0 0;margin:0 0 4px;">医学/解剖/专业词这一类怎么改</div>
