    });
    pane.querySelectorAll('[data-bpreset]').forEach(btn=>{
      btn.onclick=()=>{ const label=btn.dataset.bpreset; delete builtinPatternInstructions[label]; saveBuiltinPatternInstructions(); buildPurifyRuleTab(); showBubble('已还原句式默认规则：'+label); };
    });
    pane.querySelectorAll('[data-bptoggle]').forEach(btn=>{
