      customPurifyWords.push({word,type}); saveCustomWords(); buildPurifyRuleTab(); showBubble('✓ 已添加词条：'+word);
    };
    DOC.getElementById('ss-cp-add').onclick=()=>{
      const label=DOC.getElementById('ss-cp-label').value.trim();
      const pattern=DOC.getElementById('ss-cp-pattern').value.trim();
      const flags=DOC.getElementById('ss-cp-flags').value.trim();
      const instruction=DOC.getElementById('ss-cp-inst').value.trim();
      if(!label||!pattern||!instruction){ showBubble('请填写模式名、正则和修改规则'); return; }
      if(!safeRegExp(pattern, flags)){ showBubble('正则无效，请检查'); return; }
      if(customPurifyPatterns.some(i=>i.label===label && i.pattern===pattern)){ showBubble('该句式已存在'); return; }
      customPurifyPatterns.push({label,pattern,flags,instruction}); saveCustomPatterns(); buildPurifyRuleTab(); showBubble('✓ 已添加句式：'+label);
    };
  }


