  // ─── 净化 Observer ────────────────────────────────────────
  let purifyObserver=null, autoScanGuard='', purifyEvBound=false, purifyBusy=false;
  const AUTO_PURIFY_WRITE_GUARD_MS = 12000;
  const autoPurifyWriteGuard = Object.create(null);
  function purifyGuardHash(text){
    const s = String(text || '');
    let h = 0;
    for(let i=0;i<s.length;i++) h = ((h << 5) - h + s.charCodeAt(i)) | 0;
    return s.length + ':' + h;
  }
  function markAutoPurifyWrite(idx, raw){
    if(idx == null || idx < 0) return;
    autoPurifyWriteGuard[idx] = { hash: purifyGuardHash(raw), ts: Date.now() };
  }
  function isAutoPurifySelfWrite(idx, raw){
    const g = autoPurifyWriteGuard[idx];
    if(!g) return false;
    if(Date.now() - g.ts > AUTO_PURIFY_WRITE_GUARD_MS){ delete autoPurifyWriteGuard[idx]; return false; }
    return g.hash === purifyGuardHash(raw);
  }
  function startPurifyObserver(){
    bindPurifyEvents();
    if(purifyObserver)return;
    const chatEl=DOC.querySelector('#chat');
    if(!chatEl){ccSetTimeout(startPurifyObserver,2000);return;}
    purifyObserver=new MutationObserver(muts=>{
      for(const m of muts){
        for(const node of m.addedNodes){
          if(node.nodeType!==1)continue;
          if(!node.classList?.contains('mes'))continue;
          if(node.getAttribute('is_user')==='true')continue;
          scheduleStableScan(node);
        }
      }
    });
    purifyObserver.observe(chatEl,{childList:true,subtree:false});
    ccObservers.push(purifyObserver);
  }
  // 等这一轮 AI 正文真正写完（长度不再变）再扫，避免扫到流式输出的空壳
  function scheduleStableScan(node){
    if(!cfg.purifyEnabled && !cfg.autoFixEnabled)return;
    const txtEl=node.querySelector?.('.mes_text')||node;
    let lastLen=-1, stable=0, tries=0;
    const tick=()=>{
      if(!cfg.purifyEnabled && !cfg.autoFixEnabled)return;
      if(purifyBusy){ if(++tries<50) ccSetTimeout(tick,400); return; }
      const len=(txtEl.textContent||'').length;
      if(len>0 && len===lastLen){
        if(++stable>=2){
          const key=(node.getAttribute('mesid')||'?')+':'+len;
          if(key!==autoScanGuard){ autoScanGuard=key; checkMsg(node); }
          return;
        }
      } else { stable=0; lastLen=len; }
      if(++tries<50) ccSetTimeout(tick,400);
    };
    ccSetTimeout(tick,600);
  }

  // 监听酒馆「角色消息渲染完成」事件——AI 一说完就触发，比盯 DOM 节点可靠
  function bindPurifyEvents(){
    if(purifyEvBound)return;
    try{
      const ctx=ROOT.SillyTavern?.getContext?.();
      const es=ctx?.eventSource||ROOT.eventSource;
      const et=ctx?.event_types||ROOT.event_types;
      if(es?.on && et && et.CHARACTER_MESSAGE_RENDERED){
        es.on(et.CHARACTER_MESSAGE_RENDERED, (idx)=>{
          if(!cfg.purifyEnabled && !cfg.autoFixEnabled)return;
          if(purifyBusy)return;
          const i = typeof idx==='number' ? idx : parseInt(idx,10);
          const mesEl = getMesElByIndex(Number.isInteger(i)?i:-1) || getLatestAiTarget()?.mesEl;
          if(mesEl) ccSetTimeout(()=>{ if(!purifyBusy) checkMsg(mesEl); }, 400);
        });
        purifyEvBound=true;
      }
    }catch(e){}
  }

  function checkMsg(mesEl){
    if(!cfg.purifyEnabled && !cfg.autoFixEnabled)return;
    if(purifyBusy)return;
    const target=getTargetMessageFromEl(mesEl);
    if(target && isAutoPurifySelfWrite(target.idx, target.raw)) return;
    const text=target ? getPurifyTextFromRaw(target.raw) : '';
    if(!text){
      if(cfg.autoFixEnabled) showBubble('本轮未找到 <context>，未净化', 4000);
      return;
    }
    const found=scanForbidden(text);
    if(!found.length){
      if(cfg.autoFixEnabled) showBubble('本轮 context 未检测到净化项', 4000);
      return;
    }
    lastPurify={text,found,mesEl,idx:target.idx}; purifyCleanText='';
    updatePurifyArea();
    if(cfg.autoFixEnabled){
      showBubble('⚡ 捕获到八股词/句式 '+found.length+' 个，正在按规则请求 AI 改写…', 12000);
      ccSetTimeout(()=>autoRunPurify(), 100);
    } else {
      showBubble('⚠️ context 检测到净化项：'+found.slice(0,4).join(' · ')+(found.length>4?' 等'+found.length+'处':''),7000);
