  // 有些安卓内核“声明支持 PointerEvent”，但 pointerup/click 会丢；因此同时绑定 touch 兜底，并用时间戳去重。
  let drag=false,moved=false,ox=0,oy=0,downX=0,downY=0,downTime=0,activePointerId=null,activeTouchId=null;
  let lastPointerAt=0,lastTouchAt=0,suppressClickUntil=0,lastActivateAt=0;
