  }
  function beginBtnDrag(clientX, clientY, pointerId, touchId){
    const r=$btn.getBoundingClientRect();
    drag=true; moved=false;
    activePointerId=pointerId ?? null;
    activeTouchId=touchId ?? null;
    downX=clientX; downY=clientY; downTime=Date.now();
    ox=clientX-r.left; oy=clientY-r.top;
  }
  function moveBtnDrag(clientX, clientY){
    if(!drag) return;
    const dx=Math.abs(clientX-downX), dy=Math.abs(clientY-downY);
    if(dx>DRAG_THRESHOLD || dy>DRAG_THRESHOLD) moved=true;
    if(moved) setBtnPositionFromPoint(clientX, clientY);
  }
  function resetBtnDrag(){
    drag=false; moved=false; activePointerId=null; activeTouchId=null;
  }
  function activateBtn(){
    const now=Date.now();
    if(now-lastActivateAt<350) return; // pointer/touch/click 三路去重
    lastActivateAt=now;
    suppressClickUntil=now+500;
    toggleDrawer();
  }
  function endBtnDrag(shouldActivate=true){
    if(!drag) return;
    const wasMoved=moved;
    resetBtnDrag();
    if(shouldActivate && !wasMoved) activateBtn();
  }
  function getTrackedTouch(list){
    if(!list || !list.length) return null;
    if(activeTouchId == null) return list[0];
    for(const t of list){ if(t.identifier === activeTouchId) return t; }
    return null;
  }

  if(ROOT.PointerEvent){
    addCleanupListener($btn,'pointerdown',e=>{
      // 安卓触屏的 button 值可能不稳定；只在鼠标事件里判断左键。
      if(e.pointerType === 'mouse' && e.button !== 0) return;
      lastPointerAt=Date.now();
      beginBtnDrag(e.clientX,e.clientY,e.pointerId,null);
