    }, {passive:false,capture:true});

    addCleanupListener(DOC,'pointerup',e=>{
      if(!drag || (activePointerId!==null && e.pointerId!==activePointerId)) return;
      lastPointerAt=Date.now();
      try{$btn.releasePointerCapture(e.pointerId);}catch(_){}
