  ccDomObserver.observe(DOC.documentElement,{childList:true,subtree:true});
  ccObservers.push(ccDomObserver);

  let ccCleaned=false;
  ROOT.__ORPHEUS_CLEANUP__ = function(){
    if(ccCleaned) return;
    ccCleaned=true;
    try { stopDemo(); } catch(e) {}
    try { stopNotes(); } catch(e) {}
    try { clearTimeout(bTimer); } catch(e) {}
    ccTimers.forEach(t => { try { t.type === 'interval' ? ROOT.clearInterval(t.id) : ROOT.clearTimeout(t.id); } catch(e) {} });
    ccObservers.forEach(o => { try { o.disconnect(); } catch(e) {} });
    ccCleanupListeners.forEach(x => { try { x.target.removeEventListener(x.type, x.fn, x.opts); } catch(e) {} });
    ['cc-btn','cc-overlay','cc-drawer','cc-bubble','cc-ext-menu-item','cc-sb','cc-style'].forEach(id => { try { DOC.getElementById(id)?.remove(); } catch(e) {} });
    ROOT.__ORPHEUS_INIT__ = false;
  };
  addCleanupListener(window, 'pagehide', ROOT.__ORPHEUS_CLEANUP__);
  addCleanupListener(window, 'unload', ROOT.__ORPHEUS_CLEANUP__);
  addCleanupListener(ROOT, 'pagehide', ROOT.__ORPHEUS_CLEANUP__);
  addCleanupListener(ROOT, 'unload', ROOT.__ORPHEUS_CLEANUP__);

})();
